// ═══════════════════════════════════════
// Compara outputs zero-shot vs few-shot
// ═══════════════════════════════════════
// Accedemos a las respuestas de AMBOS HTTP Requests
// usando $('Nombre del nodo').first().json

const zeroShotResp = $('🅰️ LLM Zero-shot').first().json;
const fewShotResp = $('🅱️ LLM Few-shot').first().json;

const zeroShotRaw = zeroShotResp?.choices?.[0]?.message?.content || 'sin respuesta';
const fewShotRaw = fewShotResp?.choices?.[0]?.message?.content || 'sin respuesta';

function tryParse(s) {
  if (typeof s !== 'string') return s;
  try { return JSON.parse(s); } catch (e) {}
  const cleaned = s.replace(/^```(?:json)?\s*/i, '').replace(/\s*```\s*$/, '').trim();
  try { return JSON.parse(cleaned); } catch (e) {}
  return null;
}

return [{
  json: {
    input: $('🩺 Webhook').first().json.body,
    zeroShot: {
      raw: zeroShotRaw,
      parsed: tryParse(zeroShotRaw),
      tokens: zeroShotResp?.usage?.total_tokens || 0
    },
    fewShot: {
      raw: fewShotRaw,
      parsed: tryParse(fewShotRaw),
      tokens: fewShotResp?.usage?.total_tokens || 0
    }
  }
}];
